let fatalShown = false
function renderFatalError(error) {
  if (fatalShown) return
  fatalShown = true
  const raw = (() => {
    if (error instanceof Error) return `${error.message}\n${error.stack || ''}`.trim()
    if (typeof error === 'string') return error
    try {
      return JSON.stringify(error)
    } catch {
      return String(error)
    }
  })()
  const text = (raw || 'Unknown UI runtime error')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
  const title = 'UI runtime error'
  document.body.innerHTML = `
    <div style="height:100vh;display:flex;align-items:center;justify-content:center;background:#f8fafc;padding:24px;font-family:Segoe UI,Arial,sans-serif;color:#142033">
      <div style="max-width:920px;width:100%;background:#fff;border:1px solid #d8e2ed;border-radius:14px;padding:20px;box-shadow:0 8px 24px rgba(15,23,42,.08)">
        <h2 style="margin:0 0 10px;font-size:22px">${title}</h2>
        <p style="margin:0 0 12px;color:#475569">A interface encontrou um erro inesperado. Feche e abra o app novamente.</p>
        <pre style="margin:0;background:#0b1220;color:#dbe7ff;border-radius:10px;padding:12px;overflow:auto;max-height:48vh;white-space:pre-wrap">${text}</pre>
      </div>
    </div>
  `
}

window.addEventListener('error', (event) => {
  renderFatalError(event?.error || event?.message || 'Unhandled window error')
})
window.addEventListener('unhandledrejection', (event) => {
  renderFatalError(event?.reason || 'Unhandled promise rejection')
})

