function t(key) {
  return translations[state.locale]?.[key] ?? key
}

function parseExtensionFilter(value) {
  if (typeof value !== 'string' || !value.trim()) return []
  const seen = new Set()
  const result = []
  value
    .split(',')
    .map((part) => part.trim().toLowerCase())
    .filter((part) => part.length > 0)
    .forEach((part) => {
      const ext = part.startsWith('.') ? part : `.${part}`
      if (!seen.has(ext)) {
        seen.add(ext)
        result.push(ext)
      }
    })
  return result
}

function formatExtensionFilter(extensions) {
  if (!Array.isArray(extensions) || !extensions.length) return ''
  return extensions
    .map((ext) => String(ext || '').trim().toLowerCase())
    .filter((ext) => ext.length > 0)
    .map((ext) => (ext.startsWith('.') ? ext.slice(1) : ext))
    .join(',')
}

let noticeTimer = null
function describeError(error) {
  if (error instanceof Error && error.message) return error.message
  if (typeof error === 'string' && error.trim()) return error
  try {
    const value = JSON.stringify(error)
    return value === '{}' ? '' : value
  } catch {
    return ''
  }
}

function showNotice(key, tone = 'info', error = null) {
  state.noticeKey = key
  state.noticeTone = tone
  els.notice.hidden = false
  els.notice.className = `notice ${tone === 'error' ? 'error' : tone === 'success' ? 'success' : ''}`.trim()
  const detail = error ? describeError(error) : ''
  state.noticeDetail = detail
  const base = t(key)
  els.notice.textContent = detail ? `${base} (${detail})` : base
  if (noticeTimer) {
    window.clearTimeout(noticeTimer)
  }
  noticeTimer = window.setTimeout(() => {
    els.notice.hidden = true
    state.noticeKey = ''
    state.noticeDetail = ''
  }, 4000)
}

function call(method, ...args) {
  const api = window.pywebview?.api
  if (!api || typeof api[method] !== 'function') {
    return Promise.reject(new Error(`Bridge unavailable: ${method}`))
  }
  return api[method](...args)
}

function formatBytes(bytes) {
  if (!Number.isFinite(bytes)) return '0 B'
  const units = ['B', 'KB', 'MB', 'GB']
  let value = bytes
  let idx = 0
  while (value >= 1024 && idx < units.length - 1) {
    value /= 1024
    idx += 1
  }
  return `${value.toFixed(1)} ${units[idx]}`
}

function setTab(tab) {
  const isConverter = tab === 'converter'
  els.tabConverter.classList.toggle('active', isConverter)
  els.tabReport.classList.toggle('active', !isConverter)
  els.viewConverter.classList.toggle('active', isConverter)
  els.viewReport.classList.toggle('active', !isConverter)
}

function applyTheme() {
  const prefersDark = !!(window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches)
  const resolvedTheme = state.theme === 'system'
    ? (prefersDark ? 'dark' : 'light')
    : (state.theme === 'dark' ? 'dark' : 'light')
  document.body.classList.toggle('dark', resolvedTheme === 'dark')
  document.body.classList.toggle('light', resolvedTheme === 'light')
}

function applyDensity() {
  document.body.classList.toggle('compact', state.density === 'compact')
}

function applyI18n() {
  document.querySelectorAll('[data-i18n]').forEach((el) => {
    const key = el.dataset.i18n
    if (key) el.textContent = t(key)
  })
  els.qualityLabel.textContent = `${t('labels.quality')} (${state.config.qualidade}%)`
  els.brightnessLabel.textContent = `${t('labels.brightness')} (${state.config.brightness}%)`
  els.dropHint.textContent = t('drop.zoneHint')
  els.reportSearch.placeholder = t('reports.searchPlaceholder')
  const densityLabels = els.densitySelect?.querySelectorAll('option')
  if (densityLabels && densityLabels.length >= 1) {
    densityLabels[0].textContent = t('density.compact')
  }
  if (els.conflictOptionVersion) els.conflictOptionVersion.textContent = t('labels.conflictVersion')
  if (els.conflictOptionOverwrite) els.conflictOptionOverwrite.textContent = t('labels.conflictOverwrite')
  if (els.conflictOptionSkip) els.conflictOptionSkip.textContent = t('labels.conflictSkip')
  if (els.backupOptionBak) els.backupOptionBak.textContent = t('labels.backupBak')
  if (els.backupOptionFolder) els.backupOptionFolder.textContent = t('labels.backupFolder')
  if (state.noticeKey) {
    const base = t(state.noticeKey)
    els.notice.textContent = state.noticeDetail ? `${base} (${state.noticeDetail})` : base
  }
  if (!state.selectedReportId && !els.reportPreview.textContent.trim()) {
    els.reportPreview.textContent = t('state.selectReport')
  }
  if (els.btnRetryErrors) {
    const count = (state.status?.items || []).filter((item) => item.status === 'error').length
    els.btnRetryErrors.textContent = `${t('actions.retryErrors')} (${count})`
  }
}

function renderFiles() {
  const list = state.status?.items ?? state.files
  const totalSize = state.files.reduce((acc, item) => acc + (item.size || 0), 0)
  const suffix = state.locale === 'en-US' ? 'file(s)' : 'arquivo(s)'
  els.filesMeta.textContent = `${state.files.length} ${suffix} • ${formatBytes(totalSize)}`
  els.filesBody.innerHTML = ''

  if (!list.length) {
    els.filesEmpty.hidden = false
    return
  }

  els.filesEmpty.hidden = true
  for (const file of list) {
    const tr = document.createElement('tr')
    tr.innerHTML = `
      <td title="${file.relPath}">${file.relPath}</td>
      <td class="right">${formatBytes(file.size)}</td>
      <td class="center"><span class="status-pill">${file.status}</span></td>
    `
    els.filesBody.appendChild(tr)
  }
}

function renderProgress() {
  const status = state.status
  const total = status?.total || 0
  const completed = status?.completed || 0
  const percent = total > 0 ? Math.round((completed / total) * 100) : 0
  const failedCount = (status?.items || []).filter((item) => item.status === 'error').length
  const retryAvailable = !!status && !state.jobId && ['done', 'error'].includes(status.phase) && failedCount > 0
  els.progressBar.style.width = `${percent}%`
  els.statusPercent.textContent = `${percent}%`
  els.statusMessage.textContent = status?.message || t('state.ready')
  els.btnConvert.disabled = state.files.length === 0 || !!state.jobId
  els.btnCancel.hidden = !state.jobId
  if (els.btnRetryErrors) {
    els.btnRetryErrors.hidden = !retryAvailable
    els.btnRetryErrors.disabled = !retryAvailable
    els.btnRetryErrors.textContent = `${t('actions.retryErrors')} (${failedCount})`
  }
  const historySuffix = state.locale === 'en-US' ? 'history entries' : 'entradas no historico'
  els.historyCount.textContent = `${state.historyEntries.length} ${historySuffix}`
}

function renderHistory() {
  els.historyList.innerHTML = ''
  if (!state.historyEntries.length) {
    const empty = document.createElement('div')
    empty.className = 'history-item'
    empty.textContent = t('state.emptyHistory')
    els.historyList.appendChild(empty)
    return
  }

  state.historyEntries.slice(0, 20).forEach((entry) => {
    const row = document.createElement('div')
    row.className = 'history-item'
    row.textContent = entry.raw || ''
    els.historyList.appendChild(row)
  })
}

function readConfigFromForm() {
  state.config.formato = els.fmtWebp.classList.contains('active') ? 'webp' : 'png'
  state.config.qualidade = Number(els.quality.value)
  state.config.scan_extensions = parseExtensionFilter(els.scanExtensions.value)
  state.config.redimensionar = !!els.resize.checked
  state.config.largura_max = els.width.value ? Number(els.width.value) : null
  state.config.altura_max = els.height.value ? Number(els.height.value) : null
  state.config.recorte_1x1 = !!els.crop.checked
  state.config.batch_sizes_enabled = !!els.batchEnabled.checked
  state.config.batch_sizes = els.batchSizes.value
    .split(',')
    .map((v) => Number(v.trim()))
    .filter((v) => Number.isFinite(v) && v > 0)
  state.config.sharpen = !!els.sharpen.checked
  state.config.brightness = Number(els.brightness.value)
  state.config.manter_estrutura = !!els.keepStructure.checked
  state.config.substituir_no_lugar = !!els.replaceInPlace.checked
  state.config.conflict_policy = els.conflictPolicy.value || 'version'
  state.config.backup_enabled = !!els.backupEnabled.checked && !!state.config.substituir_no_lugar
  state.config.backup_strategy = els.backupStrategy.value || 'bak'
  state.config.output_folder = els.outputFolder.value
}

function renderConfigVisibility() {
  const resizeEnabled = !!state.config.redimensionar
  const batchEnabled = !!state.config.batch_sizes_enabled
  const outputManaged = !!state.config.manter_estrutura || !!state.config.substituir_no_lugar
  const backupSupported = !!state.config.substituir_no_lugar
  const backupEnabled = backupSupported && !!state.config.backup_enabled

  els.resizeFields.classList.toggle('is-hidden', !resizeEnabled)
  els.batchSizesWrap.classList.toggle('is-hidden', !batchEnabled)
  els.batchSizes.disabled = !batchEnabled
  els.backupEnabled.disabled = !backupSupported
  els.backupStrategyWrap.classList.toggle('is-hidden', !backupEnabled)
  els.backupStrategy.disabled = !backupEnabled
  els.outputFolderWrap.classList.toggle('is-hidden', outputManaged)
  els.outputHint.classList.toggle('is-hidden', !outputManaged)
  els.btnOutputFolder.disabled = outputManaged
}

function renderAdvancedSettings() {
  const isOpen = !!state.advancedOpen
  const advancedGroup = els.advancedToggle?.closest('.settings-group.advanced')
  if (advancedGroup) advancedGroup.classList.toggle('is-open', isOpen)
  els.advancedBody.classList.toggle('is-hidden', !isOpen)
}

function renderConfig() {
  els.presetSelect.value = state.selectedPreset || ''
  els.fmtWebp.classList.toggle('active', state.config.formato === 'webp')
  els.fmtPng.classList.toggle('active', state.config.formato === 'png')
  els.quality.value = String(state.config.qualidade)
  els.qualityLabel.textContent = `${t('labels.quality')} (${state.config.qualidade}%)`
  els.scanExtensions.value = formatExtensionFilter(state.config.scan_extensions || [])
  els.resize.checked = state.config.redimensionar
  els.width.value = state.config.largura_max ?? ''
  els.height.value = state.config.altura_max ?? ''
  els.crop.checked = state.config.recorte_1x1
  els.batchEnabled.checked = state.config.batch_sizes_enabled
  els.batchSizes.value = state.config.batch_sizes.join(',')
  els.sharpen.checked = state.config.sharpen
  els.brightness.value = String(state.config.brightness)
  els.brightnessLabel.textContent = `${t('labels.brightness')} (${state.config.brightness}%)`
  els.keepStructure.checked = state.config.manter_estrutura
  els.replaceInPlace.checked = state.config.substituir_no_lugar
  els.conflictPolicy.value = state.config.conflict_policy || 'version'
  els.backupEnabled.checked = !!state.config.backup_enabled && !!state.config.substituir_no_lugar
  els.backupStrategy.value = state.config.backup_strategy || 'bak'
  els.outputFolder.value = state.config.output_folder
  renderConfigVisibility()
  renderAdvancedSettings()
}

function renderReports() {
  els.reportsList.innerHTML = ''
  const reports = filterReports(state.reports)
  if (!reports.length) {
    els.reportsList.innerHTML = `<div class="empty" style="margin-top:40px">${t('state.noReports')}</div>`
    renderReportActionsState()
    return
  }

  for (const report of reports) {
    const item = document.createElement('button')
    item.className = `report-item ${state.selectedReportId === report.id ? 'active' : ''}`
    const generated = report.generated_at || report.generatedAt || report.id
    const sources = report.source_folders || report.sourceFolders || []
    const folderText = state.locale === 'en-US'
      ? (sources.length > 1 ? `${sources.length} folders` : (sources[0] || 'no source'))
      : (sources.length > 1 ? `${sources.length} pastas` : (sources[0] || 'sem origem'))
    const resultText = state.locale === 'en-US'
      ? `${report.success}/${report.total} ok • ${report.errors} errors`
      : `${report.success}/${report.total} ok • ${report.errors} erros`
    item.innerHTML = `
      <div class="report-title">${generated}</div>
      <div class="report-meta">${folderText}</div>
      <div class="report-meta">${resultText}</div>
    `
    item.onclick = () => selectReport(report.id)
    els.reportsList.appendChild(item)
  }
  renderReportActionsState()
}

function renderReportActionsState() {
  const hasSelected = !!state.selectedReportId
  els.openHtml.disabled = !hasSelected
  els.openAi.disabled = !hasSelected
  els.openCsv.disabled = !hasSelected
  els.openFolder.disabled = !hasSelected
  els.copyReport.disabled = !hasSelected
}

function filterReports(reports) {
  const search = state.reportSearch.trim().toLowerCase()
  const date = state.reportDate
  return reports.filter((report) => {
    const generated = String(report.generated_at || report.generatedAt || '')
    const sources = report.source_folders || report.sourceFolders || []
    const haystack = `${report.id} ${generated} ${sources.join(' ')}`.toLowerCase()
    const matchesSearch = !search || haystack.includes(search)
    const matchesDate = !date || generated.startsWith(date)
    return matchesSearch && matchesDate
  })
}

async function copyTextToClipboard(text) {
  if (!text) return false
  if (navigator.clipboard && typeof navigator.clipboard.writeText === 'function') {
    try {
      await navigator.clipboard.writeText(text)
      return true
    } catch {
      // Fall through to legacy copy path.
    }
  }
  const area = document.createElement('textarea')
  area.value = text
  area.setAttribute('readonly', 'true')
  area.style.position = 'fixed'
  area.style.left = '-9999px'
  area.style.top = '0'
  document.body.appendChild(area)
  area.focus()
  area.select()
  let ok = false
  try {
    ok = document.execCommand('copy')
  } catch {
    ok = false
  }
  document.body.removeChild(area)
  return ok
}

async function selectReport(reportId) {
  state.selectedReportId = reportId
  renderReports()
  try {
    const preview = await call('get_report_preview', reportId, 8000)
    els.reportPreview.textContent = preview || t('state.selectReport')
    renderReportActionsState()
  } catch (error) {
    els.reportPreview.textContent = t('state.selectReport')
    renderReportActionsState()
    showNotice('notice.previewFailed', 'error', error)
  }
}

async function refreshHistory() {
  try {
    const history = await call('list_history')
    state.historyEntries = history
  } catch (error) {
    state.historyEntries = []
    showNotice('notice.historyRefreshFailed', 'error', error)
  }
  renderProgress()
  renderHistory()
}

async function refreshReports() {
  try {
    state.reports = await call('list_reports')
  } catch (error) {
    state.reports = []
    showNotice('notice.reportsRefreshFailed', 'error', error)
  }
  if (state.selectedReportId && !state.reports.some((report) => report.id === state.selectedReportId)) {
    state.selectedReportId = null
    els.reportPreview.textContent = t('state.selectReport')
  }
  renderReports()
  if (state.selectedReportId) {
    await selectReport(state.selectedReportId)
  } else {
    renderReportActionsState()
  }
}

function mergeFiles(newFiles) {
  const map = new Map(state.files.map((f) => [f.path, f]))
  newFiles.forEach((file) => map.set(file.path, file))
  state.files = Array.from(map.values())
  state.status = null
  renderFiles()
  renderProgress()
}

async function ingestPaths(paths) {
  if (!paths || !paths.length) return
  try {
    const files = await call('collect_paths', paths, null, state.config.scan_extensions || null)
    mergeFiles(files)
  } catch (error) {
    showNotice('notice.collectPathsFailed', 'error', error)
    throw error
  }
}

function setDropHint(messageKey, isError = false) {
  els.dropHint.textContent = t(messageKey)
  els.dropZone.classList.toggle('error', isError)
}

function setupDropZone() {
  const activate = () => els.dropZone.classList.add('active')
  const deactivate = () => els.dropZone.classList.remove('active')

  ;['dragenter', 'dragover'].forEach((eventName) => {
    els.dropZone.addEventListener(eventName, (event) => {
      event.preventDefault()
      event.stopPropagation()
      activate()
    })
  })

  ;['dragleave', 'dragend', 'drop'].forEach((eventName) => {
    els.dropZone.addEventListener(eventName, (event) => {
      event.preventDefault()
      event.stopPropagation()
      deactivate()
    })
  })

  els.dropZone.addEventListener('drop', async (event) => {
    const dropped = Array.from(event.dataTransfer?.files || [])
    const paths = dropped
      .map((file) => file.path || '')
      .filter((path) => typeof path === 'string' && path.trim().length > 0)

    if (!paths.length) {
      setDropHint('drop.zoneNoPath', true)
      window.setTimeout(() => setDropHint('drop.zoneHint', false), 3000)
      return
    }

    try {
      await ingestPaths(paths)
      setDropHint('drop.zoneHint', false)
    } catch (error) {
      console.error(error)
      setDropHint('drop.zoneNoPath', true)
      window.setTimeout(() => setDropHint('drop.zoneHint', false), 3000)
    }
  })
}

function applyPreset(name) {
  state.selectedPreset = name || ''
  if (!name || !state.presets[name]) {
    renderConfig()
    return
  }
  const preset = state.presets[name]
  state.config.redimensionar = !!preset.resize
  state.config.largura_max = preset.width
  state.config.altura_max = preset.height
  state.config.recorte_1x1 = !!preset.crop
  state.config.qualidade = Number(preset.quality || 85)
  renderConfig()
}

function pollStatus() {
  if (!state.jobId) return
  const timer = setInterval(async () => {
    try {
      const status = await call('get_conversion_status', state.jobId)
      state.status = status
      renderFiles()
      renderProgress()

      if (['done', 'canceled', 'error'].includes(status.phase)) {
        clearInterval(timer)
        state.jobId = null
        if (status.reportId) {
          state.selectedReportId = status.reportId
          setTab('report')
          await refreshReports()
        }
        await refreshHistory()
        renderProgress()
      }
    } catch (error) {
      clearInterval(timer)
      state.jobId = null
      renderProgress()
      showNotice('notice.statusFailed', 'error', error)
    }
  }, 500)
}

function bindEvents() {
  els.tabConverter.onclick = () => setTab('converter')
  els.tabReport.onclick = () => {
    setTab('report')
    refreshReports()
  }

  els.localeSelect.onchange = async (e) => {
    state.locale = e.target.value
    applyI18n()
    renderProgress()
    renderReports()
    renderHistory()
    try {
      await call('set_preferences', { locale: state.locale })
    } catch (error) {
      showNotice('notice.preferencesSaveFailed', 'error', error)
    }
  }

  els.themeSelect.onchange = async (e) => {
    state.theme = e.target.value
    applyTheme()
    try {
      await call('set_preferences', { theme: state.theme })
    } catch (error) {
      showNotice('notice.preferencesSaveFailed', 'error', error)
    }
  }

  els.densitySelect.onchange = async (e) => {
    state.density = 'compact'
    els.densitySelect.value = 'compact'
    applyDensity()
    try {
      await call('set_preferences', { uiDensity: state.density })
    } catch (error) {
      showNotice('notice.preferencesSaveFailed', 'error', error)
    }
  }

  els.btnAddFiles.onclick = async () => {
    try {
      readConfigFromForm()
      const paths = await call('pick_files')
      await ingestPaths(paths)
    } catch (error) {
      console.error(error)
      showNotice('notice.addFilesFailed', 'error', error)
    }
  }

  els.btnScanFolder.onclick = async () => {
    try {
      readConfigFromForm()
      const folder = await call('pick_folder')
      if (!folder) return
      state.files = await call('scan_folder', folder, state.config.scan_extensions || null)
      state.status = null
      renderFiles()
      renderProgress()
    } catch (error) {
      console.error(error)
      showNotice('notice.scanFailed', 'error', error)
    }
  }

  els.btnClearFiles.onclick = () => {
    state.files = []
    state.status = null
    renderFiles()
    renderProgress()
  }

  els.btnConvert.onclick = async () => {
    if (!state.files.length || state.jobId) return
    readConfigFromForm()
    try {
      const response = await call('start_conversion', {
        files: state.files,
        config: state.config
      })
      state.jobId = response.job_id
      state.status = null
      renderProgress()
      pollStatus()
      showNotice('notice.conversionStarted', 'success')
    } catch (error) {
      console.error(error)
      showNotice('notice.conversionStartFailed', 'error', error)
    }
  }

  els.btnRetryErrors.onclick = async () => {
    if (state.jobId) return
    const failedItems = (state.status?.items || []).filter((item) => item.status === 'error' && item.path)
    if (!failedItems.length) {
      showNotice('notice.noRetryableErrors', 'info')
      return
    }
    readConfigFromForm()
    const retryFiles = failedItems.map((item) => ({
      id: item.id,
      path: item.path,
      relPath: item.relPath,
      size: Number(item.size) || 0,
      sizeAfter: 0,
      status: 'pending',
      error: '',
    }))
    try {
      const response = await call('start_conversion', {
        files: retryFiles,
        config: state.config,
      })
      state.files = retryFiles
      state.jobId = response.job_id
      state.status = null
      renderFiles()
      renderProgress()
      pollStatus()
      showNotice('notice.retryStarted', 'success')
    } catch (error) {
      showNotice('notice.retryStartFailed', 'error', error)
    }
  }

  els.btnCancel.onclick = async () => {
    if (!state.jobId) return
    try {
      await call('cancel_conversion', state.jobId)
      showNotice('notice.cancelRequested', 'info')
    } catch (error) {
      showNotice('notice.cancelFailed', 'error', error)
    }
  }

  els.btnOutputFolder.onclick = async () => {
    try {
      const folder = await call('pick_folder')
      if (!folder) return
      state.config.output_folder = folder
      renderConfig()
    } catch (error) {
      showNotice('notice.pickFolderFailed', 'error', error)
    }
  }

  els.btnRefreshReports.onclick = () => refreshReports()
  els.btnClearHistory.onclick = async () => {
    try {
      await call('clear_history')
      await refreshHistory()
      showNotice('notice.historyCleared', 'success')
    } catch (error) {
      showNotice('notice.historyClearFailed', 'error', error)
    }
  }
  els.reportSearch.oninput = (e) => {
    state.reportSearch = e.target.value || ''
    renderReports()
  }
  els.reportDate.onchange = (e) => {
    state.reportDate = e.target.value || ''
    renderReports()
  }

  async function openSelectedReport(kind) {
    if (!state.selectedReportId) return
    try {
      const response = await call('open_report', state.selectedReportId, kind)
      if (!response?.ok) {
        showNotice('notice.openReportFailed', 'error')
      }
    } catch (error) {
      showNotice('notice.openReportFailed', 'error', error)
    }
  }
  els.openHtml.onclick = () => openSelectedReport('html')
  els.openAi.onclick = () => openSelectedReport('ai')
  els.openCsv.onclick = () => openSelectedReport('csv')
  els.openFolder.onclick = () => openSelectedReport('folder')
  els.copyReport.onclick = async () => {
    const text = els.reportPreview.textContent || ''
    if (!text.trim()) {
      showNotice('notice.copyFailed', 'error')
      return
    }
    const ok = await copyTextToClipboard(text)
    showNotice(ok ? 'notice.copySuccess' : 'notice.copyFailed', ok ? 'success' : 'error')
  }

  els.presetSelect.onchange = async (e) => {
    applyPreset(e.target.value)
    try {
      await call('set_preferences', { lastPreset: state.selectedPreset })
    } catch (error) {
      showNotice('notice.preferencesSaveFailed', 'error', error)
    }
  }

  ;[
    els.quality,
    els.scanExtensions,
    els.resize,
    els.width,
    els.height,
    els.crop,
    els.batchEnabled,
    els.batchSizes,
    els.sharpen,
    els.brightness,
    els.keepStructure,
    els.replaceInPlace,
    els.conflictPolicy,
    els.backupEnabled,
    els.backupStrategy
  ].forEach((input) => {
    input.onchange = () => {
      readConfigFromForm()
      renderConfig()
    }
  })

  els.fmtWebp.onclick = () => {
    state.config.formato = 'webp'
    renderConfig()
  }
  els.fmtPng.onclick = () => {
    state.config.formato = 'png'
    renderConfig()
  }

  els.advancedToggle.onclick = () => {
    state.advancedOpen = !state.advancedOpen
    renderAdvancedSettings()
  }

  document.addEventListener('keydown', async (event) => {
    if (event.key === 'Escape' && state.jobId) {
      event.preventDefault()
      try {
        await call('cancel_conversion', state.jobId)
        showNotice('notice.cancelRequested', 'info')
      } catch (error) {
        showNotice('notice.cancelFailed', 'error', error)
      }
      return
    }

    if (!(event.ctrlKey || event.metaKey)) return
    const key = event.key.toLowerCase()

    if (key === 'o') {
      event.preventDefault()
      els.btnAddFiles.click()
      return
    }
    if (key === 'enter') {
      event.preventDefault()
      els.btnConvert.click()
      return
    }
    if (key === 'l') {
      event.preventDefault()
      els.btnClearFiles.click()
    }
  })

  setupDropZone()
}

async function init() {
  bindEvents()

  try {
    const bootstrap = await call('get_app_bootstrap')
    state.locale = bootstrap.preferences?.locale || bootstrap.locale || 'pt-BR'
    state.theme = bootstrap.preferences?.theme || 'system'
    state.density = 'compact'
    state.selectedPreset = bootstrap.preferences?.lastPreset || ''
    state.presets = bootstrap.presets || {}
    if (bootstrap.preferences?.uiDensity !== 'compact') {
      try {
        await call('set_preferences', { uiDensity: 'compact' })
      } catch {
        // no-op
      }
    }
  } catch (error) {
    showNotice('notice.bootstrapFailed', 'error', error)
    state.presets = {
      'Hero Image': { resize: true, width: 1920, height: 1080, crop: true, quality: 85 },
      'Blog Post': { resize: true, width: 1200, height: 630, crop: true, quality: 85 },
      'Thumbnail': { resize: true, width: 400, height: 300, crop: true, quality: 80 },
      'Mobile Optimized': { resize: true, width: 800, height: null, crop: false, quality: 80 },
      'Avatar/Icon': { resize: true, width: 256, height: 256, crop: true, quality: 90 },
      'Original Quality': { resize: false, width: null, height: null, crop: false, quality: 95 }
    }
  }

  els.localeSelect.value = state.locale
  els.themeSelect.value = state.theme
  els.densitySelect.value = 'compact'
  els.reportSearch.value = state.reportSearch
  els.reportDate.value = state.reportDate

  els.presetSelect.innerHTML = '<option value="">Custom</option>'
  Object.keys(state.presets).forEach((preset) => {
    const opt = document.createElement('option')
    opt.value = preset
    opt.textContent = preset
    els.presetSelect.appendChild(opt)
  })

  applyTheme()
  applyDensity()
  applyI18n()
  if (state.selectedPreset && state.presets[state.selectedPreset]) {
    applyPreset(state.selectedPreset)
  }
  if (window.matchMedia) {
    const media = window.matchMedia('(prefers-color-scheme: dark)')
    const onThemeChange = () => {
      if (state.theme === 'system') applyTheme()
    }
    if (typeof media.addEventListener === 'function') {
      media.addEventListener('change', onThemeChange)
    } else if (typeof media.addListener === 'function') {
      media.addListener(onThemeChange)
    }
  }
  renderConfig()
  renderFiles()
  renderProgress()
  await Promise.all([refreshReports(), refreshHistory()])
  setTab('converter')
}

init().catch((error) => {
  console.error(error)
  renderFatalError(error)
})
